-- Brand Mentions Database Schema & Seed Data

CREATE TABLE IF NOT EXISTS mentions (
    id TEXT PRIMARY KEY,
    query_text TEXT NOT NULL,
    model TEXT NOT NULL CHECK(model IN ('chatgpt', 'claude', 'gemini', 'perplexity')),
    mentioned BOOLEAN NOT NULL DEFAULT 0,
    position INTEGER,
    sentiment TEXT CHECK(sentiment IN ('positive', 'neutral', 'negative')),
    citation_url TEXT,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE INDEX idx_mentions_model ON mentions(model);
CREATE INDEX idx_mentions_sentiment ON mentions(sentiment);
CREATE INDEX idx_mentions_created_at ON mentions(created_at);
CREATE INDEX idx_mentions_mentioned ON mentions(mentioned);

